DROP TABLE IF EXISTS tasks CASCADE;
CREATE TABLE tasks (
  id character varying(50) NOT NULL,
  topic character varying(500) NOT NULL,
  source_materials jsonb DEFAULT '[]'::jsonb NOT NULL,
  target_formats jsonb DEFAULT '["markdown"]'::jsonb NOT NULL,
  status character varying(50) DEFAULT 'pending'::character varying NOT NULL,
  progress integer DEFAULT 0,
  current_stage character varying(100),
  outline jsonb,
  research_data jsonb,
  approval_feedback text,
  output_ids jsonb DEFAULT '[]'::jsonb,
  is_hidden boolean DEFAULT false,
  hidden_at timestamp with time zone,
  evaluation jsonb,
  competitor_analysis jsonb,
  created_at timestamp with time zone DEFAULT now(),
  updated_at timestamp with time zone DEFAULT now(),
  completed_at timestamp with time zone,
  created_by character varying(100) DEFAULT 'user'::character varying,
  is_deleted boolean DEFAULT false,
  deleted_at timestamp with time zone,
  deleted_by character varying(100),
  delete_reason text,
  will_be_purged_at timestamp with time zone,
  hidden_by character varying(100),
  final_draft text,
  final_draft_edited boolean DEFAULT false,
  final_draft_edit_id uuid,
  research_config jsonb,
  search_config jsonb DEFAULT '{}'::jsonb,
  auto_research_enabled boolean DEFAULT false,
  asset_ids jsonb DEFAULT '[]'::jsonb NOT NULL,
  sequential_review_config jsonb,
  current_review_round integer DEFAULT 0,
  review_mode character varying(20) DEFAULT 'parallel'::character varying
);
ALTER TABLE tasks ADD PRIMARY KEY (id);

