-- Data: 8 rows
INSERT INTO research_reports (id, topic_id, data_package, analysis, insights, created_at) VALUES ('842768f0-0a8e-4849-8049-0cff615000c3', 'task_a4cdabd8', '[{"url":"https://www.ccdi.gov.cn/toutiaon/202603/t20260313_479354.html","source":"www.ccdi.gov.cn","content":"## 中华人民共和国国民经济和社会发展第十五个五年规划纲要. ### *来源：新华社* *发布时间： 2026-03-13 23:00* *分享*. 中华人民共和国国民经济和社会发展第十五个五年（2026-2030年）规划纲要，根据《中共中央关于制定国民经济和社会发展第十五个五年规划的建议》编制，主要阐明国家战略意图，明确政府工作重点，引导规范社会主体行为，是“十五五”时期我国全面建设社会主义现代化国家的宏伟蓝图，是全国各族人民共同的行动纲领。. “十五五”时期在基本实现社会主义现代化进程中具有承前启后的重要地位，是夯实基础、全面发力的关键时期，必须不懈努力、接续奋斗，推动事关中国式现代化全局的战略任务取得重大突破，为基本实现社会主义现代化奠定更加坚实的基础。. “十四五”时期是全面建设社会主义现代化国家新征程的开局起步阶段，我国发展历程极不寻常、极不平凡。面对错综复杂的国际形势和艰巨繁重的国内改革发展稳定任务，以习近平同志为核心的党中央团结带领全党全国各族人民，迎难而上、砥砺前行，经受住世纪疫情严重冲击，有效应对一系列重大风险挑战，推动党和国家事业取得新的重大成就。. 新发展理念引领作用全面彰显，构建新发展格局迈出重要步伐，新质生产力稳步发展，高质量发展扎实推进。经济运行稳中有进，国内生产总值突破140万亿元，现代化产业体系建设取得重大进展，基础设施支撑能力不断提升，数字经济核心产业增加值占比超过10.5%，城乡区域发展平衡性协调性增强。科技创新成果丰硕，全社会研发经费投入强度达到2.8%，攻克一批重大关键核心技术，取得一批重大原创科技成果。全面深化改革进一步推进，落实“两个毫不动摇”的体制机制不断完善，全国统一大市场建设取得积极成效，宏观经济治理效能进一步提升。高水平对外开放不断扩大，开放型经济新体制加快形成，高质量共建“一带一路”走深走实。全过程人民民主深入发展，全面依法治国有效实施。文化事业和文化产业蓬勃发展，精神文化产品丰富多彩。民生保障扎实稳固，居民人均可支配收入年均增长5.4%，城镇新增就业累计达到6242万人，劳动年龄人口平均受教育年限达到11.3年，人均预期寿命提升至79岁以上，脱贫攻坚成果巩固拓展。绿色低碳转型步伐加快，生态环境质量持续改善，非化石能源发电装机容量超过化石能源，地级及以上城市细颗粒物（PM2.5）浓度降至28微克/立方米，地表水达到或好于Ⅲ类水体比例超过90%，森林覆盖率超过25%。国家安全能力有效提升，粮食产量迈上1.4万亿斤大台阶，社会治理效能增强，社会大局保持稳定。国防和军队建设取得重大进展。“一国两制”实践深入推进。中国特色大国外交全面拓展。全面从严治党成效显著，反腐败斗争纵深推进，党的创造力、凝聚力、战斗力明显提高。. “十四五”规划主要目标任务胜利完成，我国经济实力、科技实力、国防实力、综合国力跃上新台阶，中国式现代化迈出新的坚实步伐，第二个百年奋斗目标新征程实现良好开局。这些重大成就的取得，根本在于以习近平同志为核心的党中央领航掌舵，在于习近平新时代中国特色社会主义思想科学指引，是全党全军全国各族人民聚力攻坚、团结奋斗的结果。. 大国关系牵动国际形势，国际形势演变深刻影响国内发展，我国发展处于战略机遇和风险挑战并存、不确定难预料因素增多的时期。从国际看，世界百年变局加速演进，国际力量对比深刻调整，新一轮科技革命和产业变革加速突破，我国具备主动运筹国际空间、塑造外部环境的诸多有利因素。同时，世界变乱交织、动荡加剧，地缘冲突易发多发，全球治理赤字加重、安全问题凸显；单边主义、保护主义抬头，霸权主义和强权政治威胁上升，国际经济贸易秩序遇到严峻挑战，世界经济增长动能不足、风险积累；大国博弈更加复杂激烈，外部环境的不确定性不稳定性明显增强。. 从国内看，我国经济基础稳、优势多、韧性强、潜能大，长期向好的支撑条件和基本趋势没有变，中国特色社会主义制度优势、超大规模市场优势、完整产业体系优势、丰富人才资源优势更加彰显。同时，发展不平衡不充分问题仍然突出，周期性、结构性、体制性问题相互交织；有效需求不足，供强需弱矛盾突出，国内大循环存在卡点堵点；新旧动能转换任务艰巨；农业农村现代化相对滞后；就业和居民收入增长压力较大，民生保障存在短板弱项；人口结构变化给经济发展、社会治理等提出新课题；重点领域还有风险隐患，防范化解房地产、地方政府债务、中小金融机构等风险任务繁重。. 变局蕴含机遇，挑战激发斗志。面对国际风云变幻和各种风险挑战，必须深刻领悟“两个确立”的决定性意义，增强“四个意识”、坚定“四个自信”、做到“两个维护”，保持战略定力，增强必胜信心，积极识变应变求变，敢于斗争、善于斗争，勇于面对风高浪急甚至惊涛骇浪的重大考验，以历史主动精神克难关、战风险、迎挑战，集中力量办好自己的事，统筹布局、精心安排，巩固拓展优势、破除瓶颈制约、补强短板弱项，在激烈国际竞争中赢得战略主动，以高质量发展的确定性应对各种不确定性，续写经济快速发展和社会长期稳定两大奇迹新篇章。. 坚持马克思列宁主义、毛泽东思想、邓小平理论、“三个代表”重要思想、科学发展观，全面贯彻习近平新时代中国特色社会主义思想，深入贯彻党的二十大和二十届历次全会精神，认真落实四中全会部署，围绕全面建成社会主义现代化强国、实现第二个百年奋斗目标，以中国式现代化全面推进中华民族伟大复兴，统筹推进“五位一体”总体布局，协调推进“四个全面”战略布局，统筹国内国际两个大局，完整准确全面贯彻新发展理念，加快构建新发展格局，坚持稳中求进工作总基调，坚持以经济建设为中心，以推动高质量发展为主题，以改革创新为根本动力，以满足人民日益增长的美好生活需要为根本目的，以全面从严治党为根本保障，推动经济实现质的有效提升和量的合理增长，推动人的全面发展、全体人民共同富裕迈出坚实步伐，确保基本实现社会主义现代化取得决定性进展。. ——坚持党的全面领导。坚决维护党中央权威和集中统一领导，提高党把方向、谋大局、定政策、促改革能力，把党的领导贯穿经济社会发展各方面全过程，为我国社会主义现代化建设提供根本保证。. ——坚持人民至上。尊重人民主体地位，紧紧依靠人民，维护人民根本利益，促进社会公平正义，注重在发展中保障和改善民生，在满足民生需求中拓展发展空间，推动经济和社会协调发展、物质文明和精神文明相得益彰，让现代化建设成果更多更公平惠及全体人民。. ——坚持高质量发展。以新发展理念引领发展，因地制宜发展新质生产力，做强国内大循环，畅通国内国际双循环，统筹扩大内需和深化供给侧结构性改革，加快培育新动能，促进经济结构优化升级，做优增量、盘活存量，推动经济持续健康发展和社会全面进步。. ——坚持全面深化改革。聚焦制约高质量发展的体制机制障碍，推进深层次改革，扩大高水平开放，推动生产关系和生产力、上层建筑和经济基础、国家治理和社会发展更好相适应，持续增强发展动力和社会活力。. ——坚持有效市场和有为政府相结合。充分发挥市场在资源配置中的决定性作用，更好发挥政府作用，构建统一、开放、竞争、有序的市场体系，建设法治经济、信用经济，打造市场化法治化国际化一流营商环境，形成既“放得活”又“管得好”的经济秩序。. ——坚持统筹发展和安全。在发展中固安全，在安全中谋发展，强化底线思维，有效防范化解各类风险，增强经济和社会韧性，以新安全格局保障新发展格局。. ——高质量发展取得显著成效。在结构优化和质量提升基础上，国内生产总值增长保持在合理区间、各年度视情提出，为到2035年人均国内生产总值比2020年翻一番、达到中等发达国家水平打好基础。全要素生产率稳步提升，科技进步和制度创新对经济增长的贡献持续加大。居民消费率明显提高，内需拉动经济增长主动力作用持续增强，经济增长潜力得到充分释放。全国统一大市场建设纵深推进，超大规模市场优势持续显现。新型工业化、信息化、城镇化、农业现代化取得重大进展，现代化产业体系完整性、先进性、安全性加快提升，城乡区域发展协调性进一步增强，发展新质生产力、构建新发展格局、建设现代化经济体系取得重大突破。. ——科技自立自强水平大幅提高。国家创新体系整体效能显著提升，全社会研发经费投入年均增长7%以上，教育科技人才一体发展格局基本形成。基础研究和原始创新能力显著增强，重点领域关键核心技术快速突破，产出一批重大原创性、标志性、引领性科技成果，并跑领跑领域明显增多。科技创新和产业创新深度融合，创新驱动作用明显增强。. ——进一步全面深化改革取得新突破。国家治理体系和治理能力现代化深入推进，社会主义市场经济体制更加完善，高水平对外开放体制机制更加健全，更加公平、更有活力的市场环境加快形成，全过程人民民主制度化、规范化、程序化水平进一步提高，社会主义法治国家建设达到更高水平。. ——社会文明程度明显提升。文化自信更加坚定，主流思想舆论不断巩固壮大，社会主义核心价值观广泛践行，全民族文化创新创造活力不断激发，人民精神文化生活更加丰富，中华民族凝聚力和中华文化影响力显著增强，国家软实力持续提高。. ——人民生活品质不断提高。就业保持总体稳定，城镇调查失业率低于5.5%，高质量充分就业取得新进展。居民收入增长和经济增长同步、劳动报酬提高和劳动生产率提高同步，分配结构得到优化，中等收入群体持续扩大。劳动年龄人口平均受教育年限提高到11.7年，人民群众养老托育服务需求得到更好满足，人均预期寿命提高到80岁，社会保障制度更加优化更可持续，基本公共服务均等化水平明显提升。. ——美丽中国建设取得新的重大进展。绿色生产生活方式基本形成，碳达峰目标如期实现，单位国内生产总值二氧化碳排放降低17%，清洁低碳安全高效的新型能源体系初步建成。生态环境质量全面改善，主要污染物排放总量持续减少，地级及以上城市细颗粒物（PM2.5）浓度降至27微克/立方米以下，优良水体比例提高到85%，森林覆盖率达到25.8%，生态系统多样性稳定性持续性不断提升。. ——国家安全屏障更加巩固。国家安全体系和能力进一步加强，粮食综合生产能力达到1.45万亿斤左右，能源综合生产能力达到58亿吨标准煤，重点领域风险得到有效防范化解，社会治理和公共安全治理水平明显提高，重特大事故得到有效遏制，自然灾害防御水平显著提升，建军一百年奋斗目标如期实现，更高水平平安中国建设扎实推进。. 在此基础上再奋斗五年，到2035年实现我国经济实力、科技实力、国防实力、综合国力和国际影响力大幅跃升，人均国内生产总值达到中等发达国家水平，人民生活更加幸福美好，基本实现社会主义现代化。. 坚持把发展经济的着力点放在实体经济上，坚持智能化、绿色化、融合化方向，加快建设制造强国、质量强国、航天强国、交通强国、网络强国，保持制造业合理比重，构建以先进制造业为骨干的现代化产业体系。. 坚持因势利导、分业施策，促进重点产业化解结构性矛盾、加快向中高端升级。推动钢铁、石化、船舶等产业结构调整，做强做优精品钢材基地、一流石化基地、高端船舶和海洋工程装备基地。推进电子信息、机械装备等全产业链创新，发展高端、短缺产品，加快突破关键零部件、元器件和专用材料。扩大轻工、纺织等优质产品供给。巩固提升建筑业竞争力。推动技术改造升级，发展智能制造、绿色制造、服务型制造，加快产业模式和企业组织形态变革。发展先进制造业集群，建设国家新型工业化示范区。加强全面质量管理，深入实施制造业卓越质量工程，增强质量技术基础能力。推进标准更新升级，严格安全、环保、能效、质量等规范管理，促进市场化兼并重组，推动落后低效产能有序退出。. 实施产业基础再造工程，加快突破一批重大基础技术、工艺和产品，推进先进材料、跨尺度制造等创新应用。实施重大技术装备攻关工程，突破一批标志性重大技术装备。滚动实施制造业重点产业链高质量发展行动，建立健全产业链供应链安全风险评估和应对机制，持续增强稀土、稀有金属、超硬材料等竞争优势，加强重要战略性矿产高质高效综合利用。推进国家战略腹地建设和关键产业备份，建设战略性产业基地、物资储备基地和基础设施。建立产业基础竞争力调查制度，强化共性技术研发支撑能力。完善首台（套）、首批次、首版次应用政策。. 完善产业调控和政策体系，优化产业布局，加强要素协同保障。健全产能监测预警机制，采取规划引导、产能调控、价格治理、行业自律等措施，综合整治“内卷式”竞争。推动产业政策向普惠化和功能性转型，健全产业政策制定实施、信息披露、评估调整和退出机制。完善优质企业梯度培育体系，促进中小企业专精特新发展。合理降低制造业综合成本，加大中长期贷款和信用贷款对制造业技术创新、数智化转型、绿色发展等支持力度。实施制造业人才支持计划和专业技术人才知识更新工程，培养造就卓越工程师、大国工匠、高技能人才。. 加快新一代信息技术、新能源、新材料、智能网联新能源汽车、机器人、生物医药、高端装备、航空航天等战略性新兴产业发展，因地制宜建设各具特色、优势互补的战略性新兴产业集群，着力打造一批成长潜力大、技术含量高、渗透领域广的新兴支柱产业。拓展海洋经济发展空间，推进低空经济健康有序发展。实施新技术新产品新场景大规模应用示范行动，加大场景培育和开放力度，加快新兴产业规模化发展。鼓励发展战略性产品和服务，推进国产大飞机规模化系列化发展，加强北斗系统创新应用，扎实推进智能驾驶、新型太阳能电池、新型储能等关键技术创新，支持创新药临床使用。. 瞄准引领未来发展重点领域，构建未来产业全链条培育体系，推动量子科技、生物制造、氢能和核聚变能、脑机接口、具身智能、第六代移动通信等成为新的经济增长点。加强未来产业识别和动态调整，强化基础性、前沿性、颠覆性技术布局。建立未来产业投入增长和风险分担机制，组织实施未来产业发展示范工程，探索多元技术路线、典型应用场景、可行商业模式、市场监管规则。布局一批国家未来产业研究院和概念验证中心，依托科教资源优势突出、产业基础雄厚地区建设一批未来产业